  if (argc == 2) {
    outs() << "Reading module from '" << argv[1] << "'\n";
    M = parseIRFile(argv[1], Err, Context);
  } else {
    M = parseAssemblyString(InputIR, Err, Context);
  }
  if (!M) {
    Err.print(argv[0], errs());
    return 1;
  }

  bool HadError = false;
  for (Function &F : *M) {
    outs() << "Processing function '" << F.getName() << "'\n";
