#include "llvm/IR/LLVMContext.h"
#include "llvm/IR/Module.h"
#include "llvm/Support/Debug.h" // For errs().

#include <optional>
using namespace llvm;

static std::optional<APInt> foldIntegerBinaryOp(unsigned Opcode,
                                                const APInt &LHS,
                                                const APInt &RHS) {
  switch (Opcode) {
  case Instruction::Add:
    return LHS + RHS;
  case Instruction::Sub:
    return LHS - RHS;
  case Instruction::Mul:
    return LHS * RHS;
  case Instruction::SDiv:
    // Besides division by zero, INT_MIN / -1 is poison in LLVM IR.
    if (RHS.isZero() ||
        (LHS.isMinSignedValue() && RHS.isAllOnes()))
      return std::nullopt;
    return LHS.sdiv(RHS);
  case Instruction::UDiv:
    if (RHS.isZero())
      return std::nullopt;
    return LHS.udiv(RHS);
  case Instruction::Shl:
  case Instruction::LShr:
  case Instruction::AShr: {
    // LLVM shift instructions are poison when the shift amount is at least
    // the bit width, so there is no ConstantInt with which to replace them.
    if (RHS.uge(LHS.getBitWidth()))
      return std::nullopt;

    uint64_t ShiftAmount = RHS.getLimitedValue();
    if (Opcode == Instruction::Shl)
      return LHS.shl(ShiftAmount);
    if (Opcode == Instruction::LShr)
      return LHS.lshr(ShiftAmount);
    return LHS.ashr(ShiftAmount);
  }
  case Instruction::And:
    return LHS & RHS;
  case Instruction::Or:
    return LHS | RHS;
  case Instruction::Xor:
    return LHS ^ RHS;
  default:
    return std::nullopt;
  }
}

// Takes \p Foo and apply a simple constant propagation optimization.
// \returns true if \p Foo was modified (i.e., something had been constant
// propagated), false otherwise.
bool myConstantPropagation(Function &Foo) {
  if (Foo.empty())
    return false;

  bool Changed = false;
  bool ChangedThisScan;

  // Repeat the scan so propagation also works when a use happens to be visited
  // before the constant-producing instruction in the function's block list.
  do {
    ChangedThisScan = false;

    for (BasicBlock &BB : Foo) {
      for (auto It = BB.begin(), End = BB.end(); It != End;) {
        Instruction &I = *It++;
        auto *BinOp = dyn_cast<BinaryOperator>(&I);
        if (!BinOp || !BinOp->getType()->isIntegerTy())
          continue;

        auto *LHS = dyn_cast<ConstantInt>(BinOp->getOperand(0));
        auto *RHS = dyn_cast<ConstantInt>(BinOp->getOperand(1));
        if (!LHS || !RHS)
          continue;

        std::optional<APInt> Result =
            foldIntegerBinaryOp(BinOp->getOpcode(), LHS->getValue(),
                                RHS->getValue());
        if (!Result)
          continue;

        ConstantInt *Folded = ConstantInt::get(Foo.getContext(), *Result);
        BinOp->replaceAllUsesWith(Folded);
        BinOp->eraseFromParent();
        Changed = true;
        ChangedThisScan = true;
      }
    }
  } while (ChangedThisScan);

  return Changed;
}
